import{_ as n,o as a,c as p,a2 as l}from"./chunks/framework.DvFsUg-r.js";const d=JSON.parse('{"title":"CAT-14. 고객 서비스 & 운영","description":"","frontmatter":{"outline":[2,3]},"headers":[],"relativePath":"hermes/benchmark/customer-service.md","filePath":"hermes/benchmark/customer-service.md","lastUpdated":1781092690000}'),e={name:"hermes/benchmark/customer-service.md"};function i(c,s,t,o,r,u){return a(),p("div",null,[...s[0]||(s[0]=[l(`<h1 id="cat-14-고객-서비스-운영" tabindex="-1">CAT-14. 고객 서비스 &amp; 운영 <a class="header-anchor" href="#cat-14-고객-서비스-운영" aria-label="Permalink to &quot;CAT-14. 고객 서비스 &amp; 운영&quot;">​</a></h1><blockquote><p><strong>평가 핵심</strong>: 에이전트가 CS 응대 스크립트, FAQ, SOP, 클레임 처리 등 <strong>고객 접점 업무</strong>를 현실감 있게 작성할 수 있는가?</p></blockquote><h2 id="이-카테고리가-중요한-이유" tabindex="-1">이 카테고리가 중요한 이유 <a class="header-anchor" href="#이-카테고리가-중요한-이유" aria-label="Permalink to &quot;이 카테고리가 중요한 이유&quot;">​</a></h2><p>고객 서비스는 <strong>공감 + 정확성 + 일관성</strong>이 동시에 필요하다. 같은 불만이라도 상황에 따라 대응이 달라져야 하고, 그러면서도 회사 정책의 틀을 벗어나면 안 된다. 에이전트가 이 미묘한 균형을 잡는지 평가한다.</p><hr><h2 id="cs-01-cs-응대-스크립트-매뉴얼" tabindex="-1">CS-01. CS 응대 스크립트 매뉴얼 ⭐⭐⭐ <a class="header-anchor" href="#cs-01-cs-응대-스크립트-매뉴얼" aria-label="Permalink to &quot;CS-01. CS 응대 스크립트 매뉴얼 :star::star::star:&quot;">​</a></h2><h3 id="시나리오-배경" tabindex="-1">시나리오 배경 <a class="header-anchor" href="#시나리오-배경" aria-label="Permalink to &quot;시나리오 배경&quot;">​</a></h3><p>신규 CS 담당자가 바로 업무에 투입될 수 있는 수준의 응대 매뉴얼.</p><h3 id="프롬프트" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>이커머스 고객센터 응대 스크립트 매뉴얼을 만들어줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>서비스: 온라인 패션 쇼핑몰 &quot;스타일릭&quot;</span></span>
<span class="line"><span>- 하루 문의: 약 200건</span></span>
<span class="line"><span>- 채널: 전화 40%, 카카오톡 채팅 35%, 이메일 20%, SNS DM 5%</span></span>
<span class="line"><span>- 주요 문의: 배송(35%), 교환/반품(30%), 상품문의(20%), 결제(10%), 기타(5%)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>매뉴얼:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. 기본 응대 원칙</span></span>
<span class="line"><span>   - 인사말 / 종료 인사 (채널별 차이)</span></span>
<span class="line"><span>   - 전화: &quot;안녕하세요, 스타일릭 고객센터 OOO입니다&quot;</span></span>
<span class="line"><span>   - 채팅: 좀 더 가볍지만 정중하게</span></span>
<span class="line"><span>   - 대기 시간 안내 표준 멘트</span></span>
<span class="line"><span>   - 이관 시 멘트 (&quot;담당 부서로 연결해드리겠습니다&quot;)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 상황별 스크립트 (각 상황에 3~4개 응대 흐름)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   A. 배송 관련</span></span>
<span class="line"><span>   - &quot;배송이 언제 오나요?&quot; → 조회 후 안내</span></span>
<span class="line"><span>   - &quot;배송이 늦어요/안 와요&quot; → 사과 + 확인 + 대안</span></span>
<span class="line"><span>   - &quot;배송지 변경하고 싶어요&quot; → 가능/불가능 조건별 분기</span></span>
<span class="line"><span>   - &quot;부분 배송 왔는데 나머지는?&quot; → 분리배송 안내</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   B. 교환/반품</span></span>
<span class="line"><span>   - &quot;사이즈가 안 맞아요&quot; → 교환 절차</span></span>
<span class="line"><span>   - &quot;상품이 불량이에요&quot; → 사진 요청 → 교환/환불 분기</span></span>
<span class="line"><span>   - &quot;반품하고 싶은데 7일 지났어요&quot; → 정책 안내 (예외 처리 기준)</span></span>
<span class="line"><span>   - &quot;교환인데 원래 상품은 언제 수거해가나요?&quot; → 수거 일정</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   C. 감정적 고객 대응</span></span>
<span class="line"><span>   - 화가 많이 난 고객 → 감정 인정 → 사실 확인 → 해결안 제시</span></span>
<span class="line"><span>   - &quot;다시는 안 사&quot; → 이탈 방지 멘트 (쿠폰 제공 가능 조건)</span></span>
<span class="line"><span>   - 욕설/폭언 고객 → 경고 → 2차 경고 → 통화 종료 절차</span></span>
<span class="line"><span>   - 반복 민원 고객 → 이력 확인 → 상급자 이관 기준</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   D. 결제/환불</span></span>
<span class="line"><span>   - &quot;결제가 안 돼요&quot; → PG사별 체크포인트</span></span>
<span class="line"><span>   - &quot;환불은 언제 되나요?&quot; → 결제수단별 환불 소요 기간</span></span>
<span class="line"><span>   - &quot;이중결제 됐어요&quot; → 긴급 대응 프로세스</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 금지 표현 &amp; 대체 표현 20쌍</span></span>
<span class="line"><span>   - &quot;규정상 안 됩니다&quot; → &quot;고객님 상황을 확인해보겠습니다&quot;</span></span>
<span class="line"><span>   - &quot;저는 모릅니다&quot; → &quot;담당 부서에 확인해서 안내드리겠습니다&quot;</span></span>
<span class="line"><span>   - &quot;원래 그렇습니다&quot; → &quot;현재 저희 정책은 ~이며, 고객님 상황에 맞게 확인하겠습니다&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 이관/에스컬레이션 기준</span></span>
<span class="line"><span>   - 담당자가 해결할 수 있는 범위 (금액, 권한)</span></span>
<span class="line"><span>   - 팀장 이관 기준 (반복 민원, 법적 언급, 금액 50만원 이상)</span></span>
<span class="line"><span>   - 법무 이관 기준 (소송 언급, 소비자원 신고 언급)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>파일: \`cs/customer-service-manual.md\`</span></span></code></pre></div><h3 id="평가-포인트" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] 채널별(전화/채팅/이메일) 톤 차별화</li><li>[ ] 상황별 분기의 현실성 (모든 케이스 커버)</li><li>[ ] 감정적 고객 대응의 전문성 (감정 인정 우선)</li><li>[ ] 금지/대체 표현의 실용성</li><li>[ ] 이관 기준의 명확성</li><li>[ ] 욕설 고객 대응 절차의 법적 적절성</li><li>[ ] 신입 CS 담당자가 바로 쓸 수 있는 수준</li></ul><hr><h2 id="cs-02-faq-헬프센터-콘텐츠" tabindex="-1">CS-02. FAQ &amp; 헬프센터 콘텐츠 ⭐⭐ <a class="header-anchor" href="#cs-02-faq-헬프센터-콘텐츠" aria-label="Permalink to &quot;CS-02. FAQ &amp; 헬프센터 콘텐츠 :star::star:&quot;">​</a></h2><h3 id="시나리오-배경-1" tabindex="-1">시나리오 배경 <a class="header-anchor" href="#시나리오-배경-1" aria-label="Permalink to &quot;시나리오 배경&quot;">​</a></h3><p>고객이 스스로 답을 찾을 수 있는 셀프서비스 콘텐츠.</p><h3 id="프롬프트-1" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트-1" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>SaaS 서비스의 헬프센터 FAQ 콘텐츠를 만들어줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>서비스: &quot;팀플로우&quot; — 원격 팀 협업 도구 (화상회의 + 프로젝트 관리 + 채팅)</span></span>
<span class="line"><span>- 유료 고객: 500사 (주로 10~50인 기업)</span></span>
<span class="line"><span>- 월 CS 문의 600건 중 40%가 반복 질문</span></span>
<span class="line"><span></span></span>
<span class="line"><span>기존 반복 문의 TOP 20 기반으로 FAQ를 작성해.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>카테고리 분류:</span></span>
<span class="line"><span>1. 시작하기 (5문항)</span></span>
<span class="line"><span>   - 가입, 팀 생성, 멤버 초대, 초기 설정, 앱 설치</span></span>
<span class="line"><span>   </span></span>
<span class="line"><span>2. 요금 &amp; 결제 (5문항)</span></span>
<span class="line"><span>   - 요금제 차이, 결제 방법, 청구서, 환불, 플랜 변경</span></span>
<span class="line"><span>   </span></span>
<span class="line"><span>3. 화상회의 (4문항)</span></span>
<span class="line"><span>   - 회의 생성, 화면 공유, 녹화, 접속 오류</span></span>
<span class="line"><span>   </span></span>
<span class="line"><span>4. 프로젝트 관리 (3문항)</span></span>
<span class="line"><span>   - 보드 생성, 권한 설정, 외부 공유</span></span>
<span class="line"><span>   </span></span>
<span class="line"><span>5. 계정 &amp; 보안 (3문항)</span></span>
<span class="line"><span>   - 비밀번호 재설정, 2FA, 데이터 내보내기</span></span>
<span class="line"><span></span></span>
<span class="line"><span>각 FAQ 항목:</span></span>
<span class="line"><span>- 질문 (고객이 실제로 검색할 법한 자연스러운 문장)</span></span>
<span class="line"><span>- 답변 (단계별, 스크린샷 위치 명시: &quot;[설정 &gt; 팀 관리 &gt; 멤버 초대]&quot;)</span></span>
<span class="line"><span>- 관련 FAQ 링크 추천 2개</span></span>
<span class="line"><span>- 이래도 해결 안 되면: &quot;고객센터 문의하기&quot; CTA</span></span>
<span class="line"><span></span></span>
<span class="line"><span>추가:</span></span>
<span class="line"><span>- \`cs/troubleshooting-guide.md\` — 자주 발생하는 기술 문제 해결 가이드 5개</span></span>
<span class="line"><span>  - &quot;회의 연결이 안 돼요&quot; → 네트워크 체크 → 브라우저 → 방화벽 → ...</span></span>
<span class="line"><span>  - 각 가이드: 증상 → 원인 3가지 → 해결 순서도 (YES/NO 분기)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>파일:</span></span>
<span class="line"><span>- \`cs/faq-helpcenter.md\`</span></span>
<span class="line"><span>- \`cs/troubleshooting-guide.md\`</span></span></code></pre></div><h3 id="평가-포인트-1" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트-1" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] 질문의 자연스러움 (실제 고객 검색어 스타일)</li><li>[ ] 답변의 단계별 명확성 (1. 클릭 2. 선택 3. 완료)</li><li>[ ] 화면 경로 표기의 일관성</li><li>[ ] 트러블슈팅의 분기 논리 (YES/NO 순서도)</li><li>[ ] 카테고리 분류의 직관성</li><li>[ ] 관련 FAQ 추천의 적절성</li><li>[ ] CS 문의 40% 감소에 실제 기여할 수준인지</li></ul><hr><h2 id="cs-03-클레임-처리-보상-정책" tabindex="-1">CS-03. 클레임 처리 &amp; 보상 정책 ⭐⭐⭐ <a class="header-anchor" href="#cs-03-클레임-처리-보상-정책" aria-label="Permalink to &quot;CS-03. 클레임 처리 &amp; 보상 정책 :star::star::star:&quot;">​</a></h2><h3 id="시나리오-배경-2" tabindex="-1">시나리오 배경 <a class="header-anchor" href="#시나리오-배경-2" aria-label="Permalink to &quot;시나리오 배경&quot;">​</a></h3><p>고객 불만/클레임에 대한 체계적 처리 프로세스와 보상 기준.</p><h3 id="프롬프트-2" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트-2" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>고객 클레임 처리 프로세스와 보상 정책을 만들어줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>서비스: 음식 배달 플랫폼 &quot;배달잇&quot;</span></span>
<span class="line"><span>- 일 주문: 5만건</span></span>
<span class="line"><span>- 일 클레임: 약 500건 (1%)</span></span>
<span class="line"><span>- 클레임 유형:</span></span>
<span class="line"><span>  - 배달 지연 (30분 이상): 40%</span></span>
<span class="line"><span>  - 음식 누락/오배달: 25%</span></span>
<span class="line"><span>  - 음식 품질 (식은 음식, 쏟아짐): 20%</span></span>
<span class="line"><span>  - 결제 오류: 10%</span></span>
<span class="line"><span>  - 위생 문제 (이물질): 5%</span></span>
<span class="line"><span></span></span>
<span class="line"><span>산출물:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. \`cs/claim-process.md\` — 클레임 처리 프로세스</span></span>
<span class="line"><span>   - 접수 → 분류 → 조사 → 판단 → 보상 → 종결 → 사후관리</span></span>
<span class="line"><span>   - 각 단계별 담당자, SLA (응답 시간), 필요 조치</span></span>
<span class="line"><span>   - 긴급도 분류:</span></span>
<span class="line"><span>     - Level 1 (즉시): 위생/이물질 → 즉시 환불 + 식품안전 보고</span></span>
<span class="line"><span>     - Level 2 (4시간): 오배달/누락 → 재배달 or 환불</span></span>
<span class="line"><span>     - Level 3 (24시간): 지연, 품질 → 쿠폰 or 부분 환불</span></span>
<span class="line"><span>   - 판단 기준표 (어떤 증거가 있으면 인정, 없으면 거절)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. \`cs/compensation-policy.md\` — 보상 기준표</span></span>
<span class="line"><span>   - 클레임 유형 × 심각도별 보상 매트릭스</span></span>
<span class="line"><span>   </span></span>
<span class="line"><span>   | 유형 | 경미 | 보통 | 심각 |</span></span>
<span class="line"><span>   |------|------|------|------|</span></span>
<span class="line"><span>   | 배달 지연 (30~60분) | 쿠폰 2,000원 | 쿠폰 3,000원 | - |</span></span>
<span class="line"><span>   | 배달 지연 (60분+) | - | 배달비 환불 | 전액 환불 |</span></span>
<span class="line"><span>   | 음식 누락 (1개) | 해당 메뉴 환불 | 해당+쿠폰 | - |</span></span>
<span class="line"><span>   | 오배달 | - | 전액 환불+쿠폰 | 전액 환불+쿠폰 5,000원 |</span></span>
<span class="line"><span>   | 품질 (식음) | 쿠폰 2,000원 | 부분 환불 | 전액 환불 |</span></span>
<span class="line"><span>   | 이물질 | - | - | 전액 환불+쿠폰 10,000원+식약처 보고 |</span></span>
<span class="line"><span>   </span></span>
<span class="line"><span>   - 월 보상 한도 (남용 방지): 동일 고객 월 3회 이상 → 검토 대상</span></span>
<span class="line"><span>   - 음식점 귀책 vs 배달 귀책 구분 기준</span></span>
<span class="line"><span>   - 보상 비용 분담 (플랫폼 vs 음식점 vs 라이더)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. \`cs/claim-response-templates.md\` — 클레임 유형별 응대 템플릿 10개</span></span>
<span class="line"><span>   - 각 템플릿: 첫 응대, 조사 중 안내, 결과 통보 (인정/거절)</span></span>
<span class="line"><span>   - 거절 시 부드럽지만 명확한 표현</span></span>
<span class="line"><span>   - &quot;소비자원에 신고하겠다&quot; 대응 템플릿</span></span>
<span class="line"><span>   - SNS 공개 불만 대응 (DM으로 전환 유도)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. \`cs/claim-analytics-framework.md\` — 클레임 분석 프레임워크</span></span>
<span class="line"><span>   - 주간/월간 리포트 구조</span></span>
<span class="line"><span>   - 추적해야 할 지표: CSAT, 해결 시간, 재접수율, 보상 비용</span></span>
<span class="line"><span>   - 클레임 패턴 분석 (특정 음식점/지역/시간대 집중?)</span></span>
<span class="line"><span>   - 개선 제안 연결 (데이터 → 운영 개선)</span></span></code></pre></div><h3 id="평가-포인트-2" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트-2" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] 긴급도 분류의 합리성 (이물질 = 즉시)</li><li>[ ] 보상 매트릭스의 세밀함과 현실적 금액</li><li>[ ] 비용 분담 구조의 공정성</li><li>[ ] 남용 방지 장치 포함</li><li>[ ] 거절 템플릿의 톤 (명확하되 공격적이지 않은)</li><li>[ ] 소비자원/SNS 대응의 현실성</li><li>[ ] 분석 프레임워크의 실용성 (데이터→개선 연결)</li></ul><hr><h2 id="cs-04-sop-표준운영절차" tabindex="-1">CS-04. SOP (표준운영절차) ⭐⭐ <a class="header-anchor" href="#cs-04-sop-표준운영절차" aria-label="Permalink to &quot;CS-04. SOP (표준운영절차) :star::star:&quot;">​</a></h2><h3 id="시나리오-배경-3" tabindex="-1">시나리오 배경 <a class="header-anchor" href="#시나리오-배경-3" aria-label="Permalink to &quot;시나리오 배경&quot;">​</a></h3><p>반복 업무를 누구나 동일하게 처리할 수 있게 하는 표준 절차서.</p><h3 id="프롬프트-3" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트-3" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>아래 3가지 업무의 SOP를 만들어줘. 신입 직원이 혼자 보고 따라할 수 있어야 해.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>SOP 1: 신규 고객 온보딩</span></span>
<span class="line"><span>- 서비스: B2B SaaS (프로젝트 관리 도구)</span></span>
<span class="line"><span>- 트리거: 유료 결제 완료</span></span>
<span class="line"><span>- 절차:</span></span>
<span class="line"><span>  1. 환영 이메일 발송 (24시간 내)</span></span>
<span class="line"><span>  2. 온보딩 미팅 일정 잡기 (3일 내)</span></span>
<span class="line"><span>  3. 미팅 진행 (30분, 화상) — 체크리스트 기반</span></span>
<span class="line"><span>  4. 초기 세팅 지원 (팀 구성, 프로젝트 생성)</span></span>
<span class="line"><span>  5. 1주 후 체크인 전화</span></span>
<span class="line"><span>  6. 2주 후 설문 발송</span></span>
<span class="line"><span>  7. 1개월 후 활용도 리뷰</span></span>
<span class="line"><span>- 각 단계: 담당자, 사용 도구, 템플릿/스크립트, 체크리스트, 예외 처리</span></span>
<span class="line"><span></span></span>
<span class="line"><span>SOP 2: 장애 대응</span></span>
<span class="line"><span>- 서비스: 위 동일 SaaS</span></span>
<span class="line"><span>- 트리거: 모니터링 알림 or 고객 신고</span></span>
<span class="line"><span>- 절차:</span></span>
<span class="line"><span>  1. 장애 확인 (5분 내)</span></span>
<span class="line"><span>  2. 심각도 판단 (전체 다운 vs 일부 기능 vs 성능 저하)</span></span>
<span class="line"><span>  3. 내부 알림 (슬랙 #incident 채널)</span></span>
<span class="line"><span>  4. 고객 공지 (상태 페이지 업데이트)</span></span>
<span class="line"><span>  5. 복구 작업 + 진행 상황 업데이트 (30분마다)</span></span>
<span class="line"><span>  6. 복구 완료 공지</span></span>
<span class="line"><span>  7. 사후 분석 (Post-mortem) 일정 잡기</span></span>
<span class="line"><span>- 심각도별 에스컬레이션 기준, 대응 시간 SLA</span></span>
<span class="line"><span></span></span>
<span class="line"><span>SOP 3: 계약 갱신 프로세스</span></span>
<span class="line"><span>- 트리거: 계약 만료 90일 전</span></span>
<span class="line"><span>- 절차:</span></span>
<span class="line"><span>  1. D-90: 갱신 대상 목록 추출 + 담당자 배정</span></span>
<span class="line"><span>  2. D-75: 고객 사용 현황 분석 (활용도, 만족도, 이슈 이력)</span></span>
<span class="line"><span>  3. D-60: 갱신 제안 미팅 (가격, 업셀 기회)</span></span>
<span class="line"><span>  4. D-45: 계약서 초안 발송</span></span>
<span class="line"><span>  5. D-30: 협상 및 조건 확정</span></span>
<span class="line"><span>  6. D-14: 최종 계약서 서명</span></span>
<span class="line"><span>  7. D-7: 갱신 완료 확인 + 감사 메일</span></span>
<span class="line"><span>  8. 미갱신 시: 이탈 분석 + 인터뷰 요청</span></span>
<span class="line"><span></span></span>
<span class="line"><span>각 SOP:</span></span>
<span class="line"><span>- 플로우차트 (텍스트 기반)</span></span>
<span class="line"><span>- 단계별 상세 절차 (체크리스트 형태)</span></span>
<span class="line"><span>- 예외 상황 분기 (고객 응답 없음, 일정 조율 불가 등)</span></span>
<span class="line"><span>- 사용 도구/시스템 명시</span></span>
<span class="line"><span>- 담당자 역할 (누가 뭘 하는지)</span></span>
<span class="line"><span>- KPI (각 SOP의 성공 측정 지표)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>파일: \`cs/sop-collection.md\`</span></span></code></pre></div><h3 id="평가-포인트-3" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트-3" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] 플로우차트의 명확성</li><li>[ ] 각 단계의 시간 제한(SLA) 구체성</li><li>[ ] 예외 상황 처리의 포괄성</li><li>[ ] 장애 대응의 심각도별 분기</li><li>[ ] 계약 갱신의 D-90~D-7 타임라인 현실성</li><li>[ ] KPI 설정의 합리성</li><li>[ ] 신입이 혼자 따라할 수 있는 상세도</li></ul><hr><h2 id="cs-05-고객-여정-맵-서비스-블루프린트" tabindex="-1">CS-05. 고객 여정 맵 &amp; 서비스 블루프린트 ⭐⭐⭐ <a class="header-anchor" href="#cs-05-고객-여정-맵-서비스-블루프린트" aria-label="Permalink to &quot;CS-05. 고객 여정 맵 &amp; 서비스 블루프린트 :star::star::star:&quot;">​</a></h2><h3 id="시나리오-배경-4" tabindex="-1">시나리오 배경 <a class="header-anchor" href="#시나리오-배경-4" aria-label="Permalink to &quot;시나리오 배경&quot;">​</a></h3><p>고객 경험을 시각화하고 개선 포인트를 도출하는 문서.</p><h3 id="프롬프트-4" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트-4" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>호텔 예약 서비스의 고객 여정 맵과 서비스 블루프린트를 만들어줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>서비스: &quot;스테이북&quot; — 부티크 호텔 예약 앱</span></span>
<span class="line"><span>- 타깃: 30~40대, 여행에 돈 쓸 의향 있는 커플/가족</span></span>
<span class="line"><span>- 예약 ~ 체크아웃 전체 여정</span></span>
<span class="line"><span></span></span>
<span class="line"><span>산출물:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. \`cs/customer-journey-map.md\`</span></span>
<span class="line"><span>   </span></span>
<span class="line"><span>   여정 단계 (7단계):</span></span>
<span class="line"><span>   A. 인지 — 여행 계획 시작, 호텔 검색</span></span>
<span class="line"><span>   B. 탐색 — 앱 다운로드, 호텔 비교, 리뷰 확인</span></span>
<span class="line"><span>   C. 예약 — 날짜 선택, 결제, 확인</span></span>
<span class="line"><span>   D. 예약 후~체크인 전 — 기대, 준비, 변경사항</span></span>
<span class="line"><span>   E. 체크인 — 도착, 체크인 절차</span></span>
<span class="line"><span>   F. 체류 — 객실 이용, 부대시설, 문의/불만</span></span>
<span class="line"><span>   G. 체크아웃 &amp; 사후 — 퇴실, 리뷰 작성, 재방문 유도</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   각 단계별:</span></span>
<span class="line"><span>   - 고객 행동 (무엇을 하는가)</span></span>
<span class="line"><span>   - 접점 (어떤 채널/화면을 만나는가)</span></span>
<span class="line"><span>   - 감정 곡선 (기대↑, 불안↓, 만족↑ 등)</span></span>
<span class="line"><span>   - 페인 포인트 (짜증나는 순간)</span></span>
<span class="line"><span>   - 기회 (와우 모먼트를 만들 수 있는 지점)</span></span>
<span class="line"><span>   - 경쟁사 대비 차별화 기회</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. \`cs/service-blueprint.md\`</span></span>
<span class="line"><span>   - 여정 맵에 대응하는 백스테이지(고객이 못 보는 내부) 활동</span></span>
<span class="line"><span>   - 프론트스테이지(고객 대면) vs 백스테이지(내부 운영) 분리</span></span>
<span class="line"><span>   - 지원 시스템 (어떤 도구/시스템이 필요한지)</span></span>
<span class="line"><span>   - 실패 지점 (failure point) 식별 5개</span></span>
<span class="line"><span>   - 각 실패 지점의 예방 &amp; 복구 방안</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. \`cs/experience-improvement-plan.md\`</span></span>
<span class="line"><span>   - 여정 맵에서 도출한 개선안 TOP 5</span></span>
<span class="line"><span>   - 각 개선안: 현재 → 개선 후, 기대 효과, 비용, 우선순위</span></span>
<span class="line"><span>   - Quick Win (즉시 가능) vs 장기 투자 구분</span></span></code></pre></div><h3 id="평가-포인트-4" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트-4" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] 7단계 여정의 현실적 행동 묘사</li><li>[ ] 감정 곡선의 구체성 (어느 순간에 불안/기대/실망)</li><li>[ ] 페인 포인트의 공감 유발력</li><li>[ ] 서비스 블루프린트의 프론트/백 분리</li><li>[ ] 실패 지점 식별의 날카로움</li><li>[ ] 개선안의 실행 가능성</li><li>[ ] 전체적으로 &quot;서비스 디자인&quot; 관점의 전문성</li></ul><hr><h2 id="cs-06-voc-고객의-소리-분석-보고서" tabindex="-1">CS-06. VOC(고객의 소리) 분석 보고서 ⭐⭐ <a class="header-anchor" href="#cs-06-voc-고객의-소리-분석-보고서" aria-label="Permalink to &quot;CS-06. VOC(고객의 소리) 분석 보고서 :star::star:&quot;">​</a></h2><h3 id="시나리오-배경-5" tabindex="-1">시나리오 배경 <a class="header-anchor" href="#시나리오-배경-5" aria-label="Permalink to &quot;시나리오 배경&quot;">​</a></h3><p>수집된 고객 피드백을 분류·분석하여 인사이트를 도출.</p><h3 id="프롬프트-5" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트-5" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>아래 고객의 소리(VOC) 데이터를 분석하고 보고서를 만들어줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>먼저 \`cs/voc-data.json\`에 가상 VOC 데이터 100건 생성:</span></span>
<span class="line"><span>- 수집 기간: 2024년 3월</span></span>
<span class="line"><span>- 채널: 전화(30), 채팅(25), 이메일(20), 앱 리뷰(15), SNS(10)</span></span>
<span class="line"><span>- 분류: 칭찬(15%), 건의(25%), 불만(45%), 문의(15%)</span></span>
<span class="line"><span>- 서비스: 온라인 식료품 배달 &quot;프레시마트&quot;</span></span>
<span class="line"><span>- 각 VOC: id, date, channel, category, sentiment(positive/neutral/negative), content(한국어 1~3문장), resolved(true/false)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>현실적 VOC 예시:</span></span>
<span class="line"><span>- &quot;새벽배송 항상 정시에 와서 좋아요&quot; (칭찬)</span></span>
<span class="line"><span>- &quot;유기농 코너 종류 좀 늘려주세요 맨날 품절&quot; (건의)</span></span>
<span class="line"><span>- &quot;사과를 시켰는데 멍든 게 왔어요 사진 첨부합니다&quot; (불만)</span></span>
<span class="line"><span>- &quot;적립금 유효기간이 너무 짧아요 3개월은 해주세요&quot; (건의)</span></span>
<span class="line"><span>- &quot;배달왔는데 냉동식품이 다 녹아있었어요&quot; (불만/심각)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>분석 보고서: \`cs/voc-analysis-march-2024.md\`</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. 월간 요약</span></span>
<span class="line"><span>   - 총 접수 건수, 채널별 분포, 카테고리별 분포</span></span>
<span class="line"><span>   - 전월 대비 변화 (가상 데이터)</span></span>
<span class="line"><span>   - 감성 분석 (긍정/중립/부정 비율)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 주요 이슈 TOP 5</span></span>
<span class="line"><span>   - 각 이슈: 건수, 대표 VOC 원문 인용, 심각도, 현재 대응 상태</span></span>
<span class="line"><span>   - 예: &quot;냉동식품 해동 배달&quot; — 12건, 심각, 콜드체인 점검 필요</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 카테고리별 키워드 분석</span></span>
<span class="line"><span>   - 불만 키워드: &quot;늦음&quot;, &quot;상태&quot;, &quot;환불&quot;, &quot;안 됨&quot;</span></span>
<span class="line"><span>   - 건의 키워드: &quot;추가&quot;, &quot;더&quot;, &quot;원하다&quot;, &quot;확대&quot;</span></span>
<span class="line"><span>   - 칭찬 키워드: &quot;빠른&quot;, &quot;신선&quot;, &quot;좋아&quot;, &quot;편리&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 채널별 특성</span></span>
<span class="line"><span>   - 전화: 긴급 불만 집중</span></span>
<span class="line"><span>   - 앱 리뷰: 칭찬 비율 높지만 별점 영향 큼</span></span>
<span class="line"><span>   - SNS: 확산 위험 있는 불만</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5. 개선 제안 (VOC → 액션 연결)</span></span>
<span class="line"><span>   - 즉시 조치 (이번 주): 냉동배송 프로세스 점검</span></span>
<span class="line"><span>   - 단기 (1개월): 적립금 정책 재검토</span></span>
<span class="line"><span>   - 중기 (분기): 유기농 SKU 확대</span></span>
<span class="line"><span></span></span>
<span class="line"><span>6. 경영진 요약 (1페이지)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>분석 스크립트: \`cs/analyze_voc.py\` (JSON → 키워드 추출 → 분류 → 리포트)</span></span></code></pre></div><h3 id="평가-포인트-5" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트-5" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] VOC 데이터의 현실성 (실제 고객 말투)</li><li>[ ] 분류의 정확성 (불만/건의/칭찬)</li><li>[ ] 키워드 분석의 유의미성</li><li>[ ] TOP 5 이슈 도출의 날카로움</li><li>[ ] VOC → 액션 연결의 구체성</li><li>[ ] 채널별 특성 분석의 인사이트</li><li>[ ] 경영진 1페이지 요약의 임팩트</li></ul><hr><h2 id="cs-07-서비스-수준-협약-sla-설계" tabindex="-1">CS-07. 서비스 수준 협약 (SLA) 설계 ⭐⭐ <a class="header-anchor" href="#cs-07-서비스-수준-협약-sla-설계" aria-label="Permalink to &quot;CS-07. 서비스 수준 협약 (SLA) 설계 :star::star:&quot;">​</a></h2><h3 id="시나리오-배경-6" tabindex="-1">시나리오 배경 <a class="header-anchor" href="#시나리오-배경-6" aria-label="Permalink to &quot;시나리오 배경&quot;">​</a></h3><p>B2B 고객에게 제공할 SLA 문서 설계.</p><h3 id="프롬프트-6" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트-6" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>B2B SaaS 서비스의 SLA 문서를 만들어줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>서비스: &quot;데이터브릿지&quot; — 기업용 데이터 통합 플랫폼</span></span>
<span class="line"><span>- 고객: 중견~대기업 (연 계약 5천만원~3억원)</span></span>
<span class="line"><span>- 현재: SLA 문서가 없어서 장애 때마다 기준이 모호</span></span>
<span class="line"><span></span></span>
<span class="line"><span>SLA 문서:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. \`cs/service-level-agreement.md\`</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   A. 서비스 가용성</span></span>
<span class="line"><span>   - 목표: 월 99.9% (연간 다운타임 8.77시간 이내)</span></span>
<span class="line"><span>   - 측정 방법: 5분 간격 모니터링, 외부 모니터링 포함</span></span>
<span class="line"><span>   - 계획된 유지보수 제외 (사전 48시간 통보)</span></span>
<span class="line"><span>   - 가용성 미달 시 크레딧:</span></span>
<span class="line"><span>     - 99.9~99.5%: 월 이용료 10% 크레딧</span></span>
<span class="line"><span>     - 99.5~99.0%: 20% 크레딧</span></span>
<span class="line"><span>     - 99.0% 미만: 30% 크레딧</span></span>
<span class="line"><span>   - 크레딧 청구 절차</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   B. 응답 시간 SLA</span></span>
<span class="line"><span>   - 긴급(P1): 서비스 전면 장애 → 15분 내 첫 응답, 4시간 내 복구</span></span>
<span class="line"><span>   - 높음(P2): 핵심 기능 장애 → 1시간 내 응답, 8시간 내 복구</span></span>
<span class="line"><span>   - 보통(P3): 비핵심 기능 → 4시간 내 응답, 48시간 내 복구</span></span>
<span class="line"><span>   - 낮음(P4): 문의/개선 요청 → 24시간 내 응답</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   C. 데이터 관련 SLA</span></span>
<span class="line"><span>   - 백업: 일 1회 자동 백업, 30일 보관</span></span>
<span class="line"><span>   - RPO(복구 시점 목표): 1시간</span></span>
<span class="line"><span>   - RTO(복구 시간 목표): 4시간</span></span>
<span class="line"><span>   - 데이터 소유권: 고객 귀속</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   D. 보고 &amp; 커뮤니케이션</span></span>
<span class="line"><span>   - 월간 가용성 리포트 제공</span></span>
<span class="line"><span>   - 장애 발생 시 실시간 상태 페이지 업데이트</span></span>
<span class="line"><span>   - 주요 장애 후 5영업일 내 Post-mortem 공유</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   E. 제외 사항</span></span>
<span class="line"><span>   - 고객 귀책 (잘못된 API 호출, 비정상 트래픽 등)</span></span>
<span class="line"><span>   - 천재지변, 클라우드 제공사 장애</span></span>
<span class="line"><span>   - 베타 기능</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   F. Tier별 SLA 차등</span></span>
<span class="line"><span>   - Standard: 위 기본 SLA</span></span>
<span class="line"><span>   - Premium: 99.95%, P1 10분 응답, 전담 TAM</span></span>
<span class="line"><span>   - Enterprise: 99.99%, P1 5분 응답, 24/7 전담 지원</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. \`cs/sla-internal-playbook.md\` — 내부 대응 매뉴얼</span></span>
<span class="line"><span>   - SLA 위반 임박 시 에스컬레이션 절차</span></span>
<span class="line"><span>   - 크레딧 계산 자동화 방법</span></span>
<span class="line"><span>   - 월간 리포트 작성 가이드</span></span></code></pre></div><h3 id="평가-포인트-6" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트-6" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] 가용성 목표(99.9%)의 산업 적합성</li><li>[ ] 크레딧 구조의 공정성 (고객/제공사 양측)</li><li>[ ] P1~P4 분류와 응답시간의 현실성</li><li>[ ] RPO/RTO 설정의 기술적 합리성</li><li>[ ] Tier별 차등의 비즈니스 논리</li><li>[ ] 제외 사항의 적절한 범위</li><li>[ ] 내부 플레이북의 실용성</li></ul><hr><h2 id="cs-08-고객-세그먼트별-리텐션-전략" tabindex="-1">CS-08. 고객 세그먼트별 리텐션 전략 ⭐⭐⭐ <a class="header-anchor" href="#cs-08-고객-세그먼트별-리텐션-전략" aria-label="Permalink to &quot;CS-08. 고객 세그먼트별 리텐션 전략 :star::star::star:&quot;">​</a></h2><h3 id="시나리오-배경-7" tabindex="-1">시나리오 배경 <a class="header-anchor" href="#시나리오-배경-7" aria-label="Permalink to &quot;시나리오 배경&quot;">​</a></h3><p>고객 데이터를 기반으로 세그먼트별 맞춤 리텐션 전략 수립.</p><h3 id="프롬프트-7" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트-7" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>고객 데이터를 분석하고 세그먼트별 리텐션 전략을 만들어줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>서비스: 구독형 온라인 교육 플랫폼 &quot;런잇&quot;</span></span>
<span class="line"><span>- MAU: 25,000명</span></span>
<span class="line"><span>- 유료 구독: 8,000명 (월 19,900원)</span></span>
<span class="line"><span>- 월 이탈률: 5.5% (업계 평균 4%)</span></span>
<span class="line"><span>- 평균 구독 기간: 4.2개월 (목표 6개월)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>고객 데이터 (가상): \`cs/customer-segments.json\` 생성</span></span>
<span class="line"><span>- 8,000명의 유료 고객 데이터</span></span>
<span class="line"><span>- 필드: id, signup_date, last_login, monthly_logins, courses_completed, </span></span>
<span class="line"><span>  courses_in_progress, total_study_hours, support_tickets, nps_score, </span></span>
<span class="line"><span>  plan_type(monthly/annual), age_group, referral_source</span></span>
<span class="line"><span></span></span>
<span class="line"><span>세그먼트 분석: \`cs/retention-strategy.md\`</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. 세그먼트 정의 (RFM + 행동 기반)</span></span>
<span class="line"><span>   - Champion (충성): 매주 접속, 코스 완료 3+, NPS 높음 → 약 15%</span></span>
<span class="line"><span>   - Engaged (활발): 주 2~3회 접속, 학습 중 → 약 25%</span></span>
<span class="line"><span>   - At Risk (위험): 접속 빈도 하락, 미완료 코스 방치 → 약 20%</span></span>
<span class="line"><span>   - Dormant (휴면): 30일+ 미접속, 결제만 유지 → 약 25%</span></span>
<span class="line"><span>   - New (신규): 가입 30일 이내 → 약 15%</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 세그먼트별 이탈 위험 분석</span></span>
<span class="line"><span>   - 각 세그먼트의 이탈률</span></span>
<span class="line"><span>   - 이탈 직전 행동 패턴 (접속 빈도 변화, 학습 시간 감소)</span></span>
<span class="line"><span>   - 이탈 사유 추정</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 세그먼트별 리텐션 전략</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   Champion:</span></span>
<span class="line"><span>   - 전략: 보상 + 커뮤니티 (놓치면 안 되는 고객)</span></span>
<span class="line"><span>   - 액션: 전용 할인, 얼리 액세스, 커뮤니티 리더 초대, 후기 요청</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   Engaged:</span></span>
<span class="line"><span>   - 전략: 습관 강화 (Champion으로 승격)</span></span>
<span class="line"><span>   - 액션: 학습 리마인더, 코스 추천, 마일스톤 축하</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   At Risk:</span></span>
<span class="line"><span>   - 전략: 재참여 유도 (가장 중요한 세그먼트!)</span></span>
<span class="line"><span>   - 액션: &quot;돌아와요&quot; 이메일, 미완료 코스 리마인더, 1:1 상담 제안</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   Dormant:</span></span>
<span class="line"><span>   - 전략: 재활성화 or graceful exit</span></span>
<span class="line"><span>   - 액션: 할인 쿠폰, 새 콘텐츠 알림, 구독 일시정지 옵션</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   New:</span></span>
<span class="line"><span>   - 전략: 온보딩 강화 (첫 경험이 모든 것을 결정)</span></span>
<span class="line"><span>   - 액션: 가이드 투어, 첫 코스 추천, 3일/7일/14일 체크인</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 각 전략별 실행 계획</span></span>
<span class="line"><span>   - 이메일/푸시/인앱 메시지 타이밍</span></span>
<span class="line"><span>   - A/B 테스트 계획</span></span>
<span class="line"><span>   - 성과 측정 KPI (세그먼트별 이탈률 변화)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5. 이탈 예측 모델 설계 (개념)</span></span>
<span class="line"><span>   - 어떤 변수가 이탈을 예측하는지</span></span>
<span class="line"><span>   - 조기 경보 기준 (이 지표가 X 이하면 At Risk로 전환)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>분석 스크립트: \`cs/segment_analysis.py\`</span></span></code></pre></div><h3 id="평가-포인트-7" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트-7" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] 세그먼트 정의의 현실적 비율</li><li>[ ] At Risk 세그먼트의 중요성 인식 (이탈 직전 개입)</li><li>[ ] 세그먼트별 전략의 차별화 (같은 전략 반복 아닌)</li><li>[ ] 이메일/푸시 타이밍의 구체성</li><li>[ ] 구독 일시정지라는 graceful exit 전략</li><li>[ ] 이탈 예측 변수의 합리성</li><li>[ ] 분석 스크립트의 실행 가능성</li></ul>`,68)])])}const q=n(e,[["render",i]]);export{d as __pageData,q as default};
